return [{ json: { body: JSON.stringify({ path, content: header + report + crossLink, overwrite: true }), intelPath: path } }];

const wb = $('Webhook').first().json.body;
const date = wb.date || new Date().toISOString().split('T')[0];
const meetingName = wb.meeting_name || 'Meeting';
const resp = $input.first().json;
const extract = resp.response || '';
if (!extract) { return [{ json: { extractPath: '102 - Meeting Extracts/(extract skipped — LLM returned empty)' } }]; }

const now = new Date();
const _hTime = new Date(now.toLocaleString('en-US', {timeZone: 'Europe/Helsinki'}));
const _pad = n => String(n).padStart(2, '0');
const createdAt = `${_hTime.getFullYear()}-${_pad(_hTime.getMonth()+1)}-${_pad(_hTime.getDate())} ${_pad(_hTime.getHours())}:${_pad(_hTime.getMinutes())}`;

const safeName = meetingName.replace(/[\/\\:*?"<>|]/g, '-');
const path = `102 - Meeting Extracts/${date} ${safeName} - Key Items.md`;
const minutePath = `100 - Meeting minutes/${date} ${safeName}.md`;
const intelPath = `101 - Meeting Intelligence Reports/${date} ${safeName} - Intelligence Report.md`;

const participants = (wb.participants || []).join(', ');
const frontmatter = `---\nmeeting: "[[${minutePath}]]"\ndate: ${date}\nparticipants: [${participants}]\ntags: [meeting-extract]\n---\n\n`;
const header = `Extract created: ${createdAt}\nTemplate Version: M20.1\n\n---\n\n`;
const crossLinks = `\n\n---\n\n*[[${minutePath}]] \u00b7 [[${intelPath}]]*`;

return [{ json: { body: JSON.stringify({ path, content: frontmatter + header + extract + crossLinks, overwrite: true }), extractPath: path } }];

// H3 fix: parse action items from assembled minutes
try {
    const assembleNode = $('Assemble Minutes');
    const minutesText = assembleNode.first().json.minutes || '';

    const apRegex = /- \[ \] \*\*\*Action Point:\*\*\*/g;
    const matches = [...minutesText.matchAll(apRegex)];
    const count = matches.length;

    if (count > 0) {
        const lines = minutesText.split('\n');
        const apLines = lines.filter(l => l.trim().startsWith('- [ ] ***Action Point:***'));
        return [{ json: { hasActions: true, count: count, actionItems: apLines.join('\n') } }];
    }
    return [{ json: { hasActions: false, count: 0, actionItems: '' } }];
} catch(e) {
    // If Assemble Minutes reference fails, return 0
    return [{ json: { hasActions: false, count: 0, actionItems: '', error: e.message } }];
}

const wb = $('Webhook').first().json.body;
const date = wb.date || '';
const meetingName = wb.meeting_name || 'Meeting';
const chatId = wb.chat_id;
const safeName = meetingName.replace(/[\/\\:*?"<>|]/g, '-');
const intelPath = $('Build Intel Note Body').first().json.intelPath || '(intel not generated)';
const extractPath = $('Build Extract Note Body').first().json.extractPath || '(extract not generated)';
const apCount = $('Parse Action Items').first().json.count || 0;
const apLine = apCount > 0 ? `\n✅ <b>${apCount} action item${apCount > 1 ? 's' : ''}</b> added to Pending Actions` : '';

const text = `<b>Meeting pipeline complete</b>\n\n📋 <code>100 - Meeting minutes/${date} ${safeName}.md</code>\n🔍 <code>${intelPath}</code>\n🗂 <code>${extractPath}</code>${apLine}`;
return [{ json: { body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML' }) } }];

const webhookBody = $('Webhook').first().json.body;
const date = webhookBody.date || new Date().toISOString().split('T')[0];
const participants = webhookBody.participants;
const participantStr = Array.isArray(participants) && participants.length
    ? participants.join(', ') : 'unknown';
const meetingName = webhookBody.meeting_name || '';
const startTime = webhookBody.start_time || '';
const endTime = webhookBody.end_time || '';
const context = webhookBody.context || '';
const transcriptFull = $('Get Transcript').first().json.data;

// Two-pass architecture: speaker_map from Build Topic Segmentation Prompt, topics from Identify Topics
// Parse speaker map (resolved in pass 1, forwarded through pass 2)
const speakerMapData = $('Build Topic Segmentation Prompt').first().json.speakerMap || {};
const rawSpeakerMap = speakerMapData;

// Parse topics from pass 2 LLM response
let topics = [];
const rawTopicResp = $input.first().json.response || '';
try {
    let cleaned = rawTopicResp.trim();
    if (cleaned.startsWith('```')) {
        cleaned = cleaned.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
    }
    const parsed = JSON.parse(cleaned);
    topics = parsed.topics || [];
} catch(e) {
    // Fallback: single topic covering everything
    topics = [{name: 'Full Meeting', start: 0, end: 999999, summary: 'Complete meeting discussion'}];
}

// H2 fix: validate speaker map against known participants to prevent phantom attendees
const knownLower = participantStr.toLowerCase().split(',').map(p => p.trim()).filter(Boolean);
const speakerMap = {};
for (const [label, name] of Object.entries(rawSpeakerMap)) {
    // Accept if label is already a real name (biometric match from voice recognition)
    if (!label.startsWith('SPEAKER_') && label !== 'Unknown') {
        speakerMap[label] = name;
        continue;
    }
    // Check if LLM-assigned name matches a known participant
    const nameLower = name.toLowerCase();
    const isKnown = knownLower.some(p => {
        const parts = p.split(' ');
        return parts.some(part => part.length > 2 && nameLower.includes(part));
    });
    speakerMap[label] = isKnown ? name : label;
}

// Build speaker map comment
const mapEntries = Object.entries(speakerMap).map(([k, v]) => `${k} = ${v}`).join(', ');
const speakerComment = `<!-- Speaker map: ${mapEntries} -->`;

// Apply speaker names to transcript lines
let resolvedTranscript = transcriptFull;
for (const [label, name] of Object.entries(speakerMap)) {
    resolvedTranscript = resolvedTranscript.replaceAll(`[${label}]`, `[${name}]`);
}

// Slice transcript by timestamps
// Parse transcript lines to find timestamps — format: [HH:MM:SS.mmm --> HH:MM:SS.mmm] or [start - end]
const lines = resolvedTranscript.split('\n');

function timeToSeconds(timeStr) {
    // Handle formats like "00:01:30.500" or "90.5"
    const parts = timeStr.trim().split(':');
    if (parts.length === 3) {
        return parseFloat(parts[0]) * 3600 + parseFloat(parts[1]) * 60 + parseFloat(parts[2]);
    } else if (parts.length === 2) {
        return parseFloat(parts[0]) * 60 + parseFloat(parts[1]);
    }
    return parseFloat(timeStr) || 0;
}

// Build line-timestamp mapping
const lineTimestamps = [];
let lastTimestamp = 0;
const tsRegex = /\[(\d[\d:.]+)\s*(?:-->|->|\u2013|\u2014|-)\s*(\d[\d:.]+)\]/;
for (const line of lines) {
    const match = line.match(tsRegex);
    if (match) {
        lastTimestamp = timeToSeconds(match[1]);
    }
    lineTimestamps.push({line, timestamp: lastTimestamp});
}

// For each topic, extract relevant lines
const topicItems = [];
for (let i = 0; i < topics.length; i++) {
    const topic = topics[i];
    const tStart = topic.start || 0;
    const tEnd = topic.end || 999999;

    const topicLines = lineTimestamps
        .filter(lt => lt.timestamp >= tStart && lt.timestamp <= tEnd)
        .map(lt => lt.line);

    const topicTranscript = topicLines.join('\n');

    topicItems.push({
        json: {
            topicIndex: i,
            topicName: topic.name,
            topicSummary: topic.summary || '',
            topicTranscript: topicTranscript,
            totalTopics: topics.length,
            speakerComment: speakerComment,
            speakerMap: speakerMap,
            date: date,
            meetingName: meetingName,
            startTime: startTime,
            endTime: endTime,
            participantStr: participantStr,
            context: context,
        }
    });
}

// H1 fix: catch orphaned lines past the last topic's end timestamp
if (topicItems.length > 0) {
    const coveredMax = Math.max(...topics.map(t => t.end || 0));
    const orphanLines = lineTimestamps
        .filter(lt => lt.timestamp > coveredMax)
        .map(lt => lt.line)
        .filter(l => l.trim());
    if (orphanLines.length > 0) {
        // Append orphans to the last topic
        const lastItem = topicItems[topicItems.length - 1];
        lastItem.json.topicTranscript += '\n' + orphanLines.join('\n');
    }
}

// If no topics extracted, pass through entire transcript as single topic
if (topicItems.length === 0) {
    topicItems.push({
        json: {
            topicIndex: 0,
            topicName: 'Full Meeting',
            topicSummary: 'Complete meeting discussion',
            topicTranscript: resolvedTranscript,
            totalTopics: 1,
            speakerComment: speakerComment,
            speakerMap: speakerMap,
            date: date,
            meetingName: meetingName,
            startTime: startTime,
            endTime: endTime,
            participantStr: participantStr,
            context: context,
        }
    });
}

return topicItems;

const item = $input.item.json;
const bodyObj = JSON.parse(item.body);

// Call Ollama via n8n built-in HTTP helper
const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:11434/api/generate',
    body: bodyObj,
    headers: {'Content-Type': 'application/json'},
    timeout: 600000,
    returnFullResponse: false,
    json: true,
});

return {
    json: {
        response: result.response || '',
        topicIndex: item.topicIndex,
        topicName: item.topicName,
        totalTopics: item.totalTopics,
    }
};

const items = $input.all();

// Get metadata from first item's input
const firstInput = $('Slice Topics').first().json;
const date = firstInput.date;
const meetingName = firstInput.meetingName;
const startTime = firstInput.startTime;
const endTime = firstInput.endTime;
const participantStr = firstInput.participantStr;
const speakerComment = firstInput.speakerComment;
const speakerMap = firstInput.speakerMap || {};
const context = firstInput.context || '';

// Build attendees from speaker map
const attendees = new Set();
attendees.add('[[Rantala Petri]]');
for (const name of Object.values(speakerMap)) {
    if (name && name !== 'Unknown' && !name.startsWith('SPEAKER_')) {
        attendees.add(`[[${name}]]`);
    }
}
const attendeeLines = [...attendees].map(a => `- [x] ${a}`).join('\n');

// Sort topic results by index
const sorted = items.map(i => ({
    index: i.json.topicIndex || 0,
    name: i.json.topicName || 'Topic',
    content: i.json.response || '',
})).sort((a, b) => a.index - b.index);

// Build descriptive meeting summary — first meaningful line from each topic
const summaryLines = sorted.map(t => {
    const lines = (t.content || '').split('\n');
    const desc = lines.find(l => l.trim() && !l.startsWith('#') && !l.startsWith('<') && !l.startsWith('**Key') && !l.startsWith('**Outcome'));
    return `- **${t.name}:** ${desc || t.name}`;
}).join('\n');

// Build agenda with wikilinks to headings
const agenda = sorted.map(t => `- [[#${t.name}]]`).join('\n');

// Build notes body from all topic analyses
const notesBody = sorted.map(t => t.content).join('\n\n');

// Assemble full minutes
const minutes = `${speakerComment}

---
- **Date:** [[${date}]]
- **Start Time:** ${startTime || 'unknown'}
- **End Time:** ${endTime || 'unknown'}
- **Attendees:**
${attendeeLines}

#### Link(s) to project(s) or note(s) if any
-

## Meeting Summary
${summaryLines}

## Agenda
${agenda}

## Notes

${notesBody}

## Screenshots
`;

return [{ json: { minutes: minutes } }];

const webhookBody = $('Webhook').first().json.body;
const date = webhookBody.date || new Date().toISOString().split('T')[0];
const meetingName = webhookBody.meeting_name || 'Meeting';

const minutes = $input.first().json.minutes;

if (!minutes) {
    throw new Error('No minutes assembled');
}

const now = new Date();
const _hTime = new Date(now.toLocaleString('en-US', {timeZone: 'Europe/Helsinki'}));
const _pad = n => String(n).padStart(2, '0');
const createdAt = `${_hTime.getFullYear()}-${_pad(_hTime.getMonth()+1)}-${_pad(_hTime.getDate())} ${_pad(_hTime.getHours())}:${_pad(_hTime.getMinutes())}`;

const header = `<div style="font-size: 0.5em;"> These notes were created using a temporary audio recording of a meeting held on ${date}. The audio was transcribed using a cloud-based service to support accurate note-taking. The recording was deleted immediately after transcription. The final document is stored locally and not shared externally. </div>

Minutes created: ${createdAt} © Petri Rantala
Tags: #📓 ⚖ ✅ 🤝
Template Version: 2.0-v2
Pipeline: divide-and-conquer (M59)

---

`;

const safeName = meetingName.replace(/[\/\\:*?"<>|]/g, '-');
const path = `100 - Meeting minutes/${date} ${safeName}.md`;
const intelPath = `101 - Meeting Intelligence Reports/${date} ${safeName} - Intelligence Report.md`;
const crossLink = `\n\n---\n\n*Intelligence Report: [[${intelPath}]]*`;
return [{ json: { body: JSON.stringify({ path, content: header + minutes + crossLink, overwrite: true }) } }];

// Fan out: one intel prompt per topic using the already-analyzed topic content
const topicResults = $('Analyze Topic').all();
const wb = $('Webhook').first().json.body;
const participants = wb.participants || [];
const participantStr = Array.isArray(participants) && participants.length ? participants.join(', ') : 'unknown';
const date = wb.date || new Date().toISOString().split('T')[0];

const systemPrompt = `You are a meeting intelligence analyst. For this SINGLE TOPIC, identify:
1. Key behavioral signals (who said what, tone, hedging, confidence levels)
2. Power dynamics and influence patterns
3. Hidden concerns or unspoken risks
4. Deception or withholding indicators (with confidence %)
5. Motivations and drivers for each speaker

Be evidence-based: cite specific quotes or paraphrases with speaker attribution.
Use wikilinks for person names: [[Lastname Firstname]] (family name first, ALWAYS reorder — e.g. "Johanna Aivio" becomes [[Aivio Johanna]]). First-name-only = plain text, no wikilink.
Output concise markdown (max 500 words). No preamble.`;

const items = topicResults.map(item => {
    const topicContent = item.json.response || '';
    const topicName = item.json.topicName || 'Topic';
    const topicIndex = item.json.topicIndex || 0;

    // Get the original topic transcript from Slice Topics
    const sliceItems = $('Slice Topics').all();
    const sliceItem = sliceItems.find(s => s.json.topicIndex === topicIndex);
    const topicTranscript = sliceItem ? sliceItem.json.topicTranscript || '' : '';

    // Cap per-topic transcript for 8b model
    const MAX_CHARS = 20000;
    const safeTranscript = topicTranscript.length > MAX_CHARS
        ? topicTranscript.substring(0, MAX_CHARS) + '\n[...truncated...]'
        : topicTranscript;

    const userMsg = `Topic: ${topicName}\nParticipants: ${participantStr}\nDate: ${date}\n\n## Meeting Minutes (this topic)\n${topicContent}\n\n## Raw Transcript (this topic)\n${safeTranscript}`;

    return {
        json: {
            topicIndex: topicIndex,
            topicName: topicName,
            body: JSON.stringify({
                model: 'qwen3:8b',
                stream: false,
                think: false,
                num_ctx: 32768,
                system: systemPrompt,
                prompt: userMsg
            })
        }
    };
});

return items;

const item = $input.item.json;
const bodyObj = JSON.parse(item.body);

const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:11434/api/generate',
    body: bodyObj,
    headers: {'Content-Type': 'application/json'},
    timeout: 600000,
    returnFullResponse: false,
    json: true,
});

return {
    json: {
        topicIntel: result.response || '',
        topicIndex: item.topicIndex,
        topicName: item.topicName,
    }
};

const webhookBody = $('Webhook').first().json.body;
const participants = webhookBody.participants;
const participantStr = Array.isArray(participants) && participants.length
    ? participants.join(', ') : 'unknown';
const rawTranscript = $('Get Transcript').first().json.data || '';

// Full transcript for speaker ID — even 83-min meetings (72k chars) fit in 32k tokens
// Prompt eval dominates (~220s), generation is tiny (~50 tokens)
const MAX_CHARS = 75000;
const transcript = rawTranscript.length > MAX_CHARS
