// Parse speaker map from previous pass
let speakerMap = {};
const speakerResp = $input.first().json.response || '';
try {
    let cleaned = speakerResp.trim();
    if (cleaned.startsWith('```')) {
        cleaned = cleaned.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
    }
    const parsed = JSON.parse(cleaned);
    speakerMap = parsed.speaker_map || {};
} catch(e) {
    // No speaker map — proceed with original labels
}

// Apply speaker names to transcript for better topic identification
let resolvedTranscript = rawTranscript;
for (const [label, name] of Object.entries(speakerMap)) {
    resolvedTranscript = resolvedTranscript.replaceAll('[' + label + ']', '[' + name + ']');
}

// Full transcript — same budget as speaker ID pass
const MAX_CHARS = 75000;
const transcript = resolvedTranscript.length > MAX_CHARS
    ? resolvedTranscript.substring(0, MAX_CHARS) + '\n\n[... truncated ...]'
    : resolvedTranscript;

