const fs = require('fs');
let queueId = 'unknown';
let meetingName = '';
try {
    const wb = $('Webhook').first().json.body;
    queueId = wb.queue_id || 'unknown';
    meetingName = wb.meeting_name || '';
} catch(e) {
    // Error trigger may not have Webhook context — try execution data
    try {
        const execData = $input.first().json;
        // Look for queue_id in the execution metadata
        if (execData.execution && execData.execution.data) {
            const triggerData = execData.execution.data.resultData?.runData?.Webhook;
            if (triggerData) {
                const body = triggerData[0]?.data?.main?.[0]?.[0]?.json?.body;
                if (body) {
                    queueId = body.queue_id || 'unknown';
                    meetingName = body.meeting_name || '';
                }
            }
        }
    } catch(e2) {}
}
const doneDir = '/data/pipeline_done';
try { fs.mkdirSync(doneDir, { recursive: true }); } catch(e) {}
const errorMsg = $input.first().json.execution?.error?.message || 'unknown error';
fs.writeFileSync(doneDir + '/' + queueId + '.json', JSON.stringify({
    queue_id: queueId,
    meeting_name: meetingName,
    status: 'failed',
    completed_at: new Date().toISOString(),
    error: errorMsg
}));
return [{json: {queue_id: queueId, status: 'failed', error: errorMsg}}];
